INSERT INTO public.app_facts (category, subcategory, subcategory_level2, text, icon) VALUES
('penis', '🧬 Lidská anatomie a biologie', '🧱 Základní stavba a tkáně', 'Na rozdíl od mnoha jiných savců nemá lidský penis žádnou kost (tzv. bakulum). Ztvrdne výhradně díky krevnímu tlaku (hemodynamický děj).', '🧱'),
('penis', '🧬 Lidská anatomie a biologie', '🧱 Základní stavba a tkáně', 'Uvnitř penisu se nacházejí tři houbovitá topořivá tělesa: dvě horní (corpora cavernosa) a jedno spodní (corpus spongiosum), kterým prochází močová trubice a na konci se rozšiřuje do žaludu.', '🧱'),
('penis', '🧬 Lidská anatomie a biologie', '🧱 Základní stavba a tkáně', 'Obal topořivých těles (tunica albuginea) je neuvěřitelně pevná dvourstvá vazivová blána. Pokud dojde k jejímu natržení při prudkém ohybu ztopořeného penisu, vzniká takzvaná zlomenina penisu.', '🧱'),
('penis', '🧬 Lidská anatomie a biologie', '🧱 Základní stavba a tkáně', 'U žaludu je tento pevný obal mnohem tenčí, což mu umožňuje fungovat při sexuálním styku jako měkký, ochranný nárazník.', '🧱'),
('penis', '🧬 Lidská anatomie a biologie', '🧱 Základní stavba a tkáně', 'Všechna tři tělesa drží pevně pohromadě a kruhový tvar jim dává silná vrstva vaziva zvaná Buckova fascie.', '🧱'),
('penis', '🧬 Lidská anatomie a biologie', '🧱 Základní stavba a tkáně', 'Zhruba polovina celkové délky penisu není zvenčí vůbec vidět. Takzvaný kořen penisu (bulbus) je skrytý hluboko v hrázi (perineu) a je pevně připojen k pánevní kosti.', '🧱'),
('penis', '🧬 Lidská anatomie a biologie', '🧱 Základní stavba a tkáně', 'Penis je ve své pozici ukotven díky silnému závěsnému vazu (ligamentum suspensorium). Pokud se chirurgicky přeruší za účelem prodloužení ochablého penisu, vede to často k jeho nestabilitě.', '🧱'),
('penis', '🧬 Lidská anatomie a biologie', '🧱 Základní stavba a tkáně', 'V samotném vnějším penisu nejsou žádné příčně pruhované svaly, které by šlo vědomě zatnout. Veškerý pohyb obstarávají svaly pánevního dna u jeho kořene (např. musculus ischiocavernosus a bulbocavernosus).', '🧱'),
('penis', '🧬 Lidská anatomie a biologie', '🩸 Krevní oběh a mechanismus erekce', 'Erekce je řízena parasympatickým nervovým systémem, který pomocí molekul oxidu dusnatého (NO) uvolní hladkou svalovinu v cévách penisu a umožní masivní přítok krve.', '🩸'),
('penis', '🧬 Lidská anatomie a biologie', '🩸 Krevní oběh a mechanismus erekce', 'Uvnitř se nacházejí takzvané helikinní tepny. V ochablém stavu jsou stočené do spirály, ale při vzrušení se narovnají a zaplaví tělesa krví.', '🩸'),
('penis', '🧬 Lidská anatomie a biologie', '🩸 Krevní oběh a mechanismus erekce', 'Aby erekce vydržela, naplněná topořivá tělesa se roztáhnou a mechanicky přimáčknou drobné odvodové žíly proti pevnému zevnímu obalu. Tím se uvnitř těla doslova zablokuje odtok krve.', '🩸'),
('penis', '🧬 Lidská anatomie a biologie', '🩸 Krevní oběh a mechanismus erekce', 'Spodní topořivé těleso neztvrdne pod tak obrovským tlakem jako obě horní. Tím je zajištěno, že močová trubice nezůstane zaškrcená a semeno jím může bezpečně projít.', '🩸'),
('penis', '🧬 Lidská anatomie a biologie', '🩸 Krevní oběh a mechanismus erekce', 'Úhel ztopořeného penisu (od přilehnutí k břichu až po směřování dolů) je zcela individuální a závisí na pevnosti a napětí závěsných vazů.', '🩸'),
('penis', '🧬 Lidská anatomie a biologie', '🩸 Krevní oběh a mechanismus erekce', 'Hmotnost penisu v ochablém stavu je zhruba 100 až 200 gramů. Během erekce se tato váha zvýší o dalších 50 až 80 mililitrů napumpované krve.', '🩸'),
('penis', '🧬 Lidská anatomie a biologie', '🩸 Krevní oběh a mechanismus erekce', 'Po ejakulaci dochází k takzvané detumescenci (ochabnutí). Hladká svalovina se znovu stáhne, odvodové žíly se otevřou a krev z penisu odteče.', '🩸'),
('penis', '🧬 Lidská anatomie a biologie', '🩸 Krevní oběh a mechanismus erekce', 'Stres, strach nebo extrémní chlad aktivují sympatický nervový systém, který cévy naopak stáhne, což dosažení erekce okamžitě znemožní.', '🩸'),
('penis', '🧬 Lidská anatomie a biologie', '🧠 Nervový systém a citlivost', 'Předkožka a žalud mají nejvyšší hustotu nervových zakončení. Nejcitlivějším místem celého penisu je u většiny mužů uzdička (frenulum).', '🧠'),
('penis', '🧬 Lidská anatomie a biologie', '🧠 Nervový systém a citlivost', 'V penisu se nacházejí tři typy senzorů: volná nervová zakončení (pro bolest a teplotu), Meissnerova tělíska (pro jemný dotek) a Paciniho tělíska (pro hluboký tlak, vibrace a rychlost tření).', '🧠'),
('penis', '🧬 Lidská anatomie a biologie', '🧠 Nervový systém a citlivost', 'Bezprostředně po orgasmu se penis často stává extrémně přecitlivělým na dotek (hyperalgézie). Jde o fyziologický ochranný mechanismus těla proti další, už nepotřebné stimulaci.', '🧠'),
('penis', '🧬 Lidská anatomie a biologie', '🧠 Nervový systém a citlivost', 'Citlivost penisu s věkem přirozeně mírně klesá (nejvýrazněji po 40. roce). Zdravotní problémy jako diabetes navíc poškozují nervy a mohou vést k další ztrátě citlivosti žaludu.', '🧠'),
('penis', '🧬 Lidská anatomie a biologie', '🧬 Vývoj a genetika', 'V raném stádiu vývoje plodu (do 8. týdne) mají muži i ženy naprosto stejný genitální základ. Penis a ženský klitoris jsou tedy z biologického hlediska přímí protějšci.', '🧬'),
('penis', '🧬 Lidská anatomie a biologie', '🧬 Vývoj a genetika', 'Vývoj mužských genitálií je spouštěn genem SRY na chromozomu Y. K samotnému formování penisu dochází mezi 8. a 14. týdnem vlivem dihydrotestosteronu (DHT).', '🧬'),
('penis', '🧬 Lidská anatomie a biologie', '🧬 Vývoj a genetika', 'Nedostatek enzymu potřebného k tvorbě DHT v děloze může u plodu vést k vývoji nejednoznačných genitálií nebo takzvaného mikropenisu.', '🧬'),
('penis', '🧬 Lidská anatomie a biologie', '🧬 Vývoj a genetika', 'První erekce se objevují u chlapečků už v matčině děloze a na ultrazvuku bývají prokazatelně viditelné zhruba od 16. týdne těhotenství.', '🧬'),
('penis', '🧬 Lidská anatomie a biologie', '🧬 Vývoj a genetika', 'Tmavší linie, která se táhne přes šourek a podél spodní strany penisu (tzv. raphe penis), je pozůstatkem srůstu embryonálních tkání.', '🧬'),
('penis', '🧬 Lidská anatomie a biologie', '🧬 Vývoj a genetika', 'Během evoluce ztratili lidé drobné keratinové „ostny“ na penisu. Šimpanzi je stále mají – pomáhají jim při páření mechanicky odstranit spermie případných konkurentů.', '🧬'),
('penis', '🧬 Lidská anatomie a biologie', '🛌 Spánek a chlad', 'Zdravý muž má během nočního spánku (zejména v REM fázi) 3 až 6 samovolných erekcí, přičemž každá trvá zhruba 20 až 40 minut.', '🛌'),
('penis', '🧬 Lidská anatomie a biologie', '🛌 Spánek a chlad', 'Noční erekce slouží jako údržbový systém, kterým si tělo tkáň penisu pravidelně protahuje a zásobuje ji okysličenou krví.', '🛌'),
('penis', '🧬 Lidská anatomie a biologie', '🛌 Spánek a chlad', 'Známé ranní ztopoření je obvykle jen úplně poslední z této série přirozených nočních erekcí (ačkoliv plný močový měchýř může tento reflex mechanicky podpořit).', '🛌'),
('penis', '🧬 Lidská anatomie a biologie', '🛌 Spánek a chlad', 'Chlad má na penis extrémní vliv. Pomocí dartosové svaloviny a kremasterového reflexu se penis a šourek okamžitě stáhnou co nejblíže k teplu břišní dutiny, aby chránily varlata.', '🛌'),
('penis', '🧬 Lidská anatomie a biologie', '🔬 Kůže a povrchové útvary', 'Kůže na penisu a šourku bývá často o 1 až 2 odstíny tmavší než zbytek těla v důsledku stimulace pigmentových buněk (melanocytů) androgenními hormony v pubertě.', '🔬'),
('penis', '🧬 Lidská anatomie a biologie', '🔬 Kůže a povrchové útvary', 'Kůže kmene penisu zcela postrádá podkožní tukovou vrstvu a díky velmi řídké Dartosově fascii je vysoce volná a pohyblivá, což umožňuje extrémní roztažení při ztopoření.', '🔬'),
('penis', '🧬 Lidská anatomie a biologie', '🔬 Kůže a povrchové útvary', 'Žalud a vnitřní strana předkožky fungují společně jako měkká sliznice. U obřezaných mužů bez této ochrany vnější povrch žaludu zhrubne, vysuší se (keratinizuje) a mírně ztratí na povrchové citlivosti.', '🔬'),
('penis', '🧬 Lidská anatomie a biologie', '🔬 Kůže a povrchové útvary', 'Tysonovy žlázy na spodní straně žaludu produkují smegma – přirozený bělavý lubrikant tvořený odumřelými kožními buňkami a mazem, který má ochrannou funkci.', '🔬'),
('penis', '🧬 Lidská anatomie a biologie', '🔬 Kůže a povrchové útvary', 'Drobné bílé tečky (Fordyceovy skvrny) nebo malé hrbolky v korunce žaludu (perleťové papily) jsou naprosto přirozené anatomické varianty mazových žláz, nikoliv infekce či nemoc.', '🔬'),
('penis', '🧬 Lidská anatomie a biologie', '🔬 Kůže a povrchové útvary', 'Díky enormnímu prokrvení oblasti se kůže na penisu a genitáliích obecně hojí a regeneruje mnohem rychleji než kůže na zbytku těla.', '🔬'),
('penis', '🧬 Lidská anatomie a biologie', '⚠️ Zajímavé anomálie a další specifika', 'Délka ochablého penisu nijak nekoreluje s velikostí při erekci. Záleží na fyziologii – tzv. „growers“ mohou svou velikost při vzrušení zvětšit až o 100 %.', '⚠️'),
('penis', '🧬 Lidská anatomie a biologie', '⚠️ Zajímavé anomálie a další specifika', 'Většina penisů není dokonale rovná. Drobná vrozená asymetrie topořivých těles, způsobující mírné naklonění či prohnutí ztopořeného penisu, se vyskytuje asi u 10 % mužů a je normální.', '⚠️'),
('penis', '🧬 Lidská anatomie a biologie', '⚠️ Zajímavé anomálie a další specifika', 'Močová trubice nefunguje jen jako pasivní hadice. Obsahuje drobné Littreho žlázky produkující hlen pro zvlhčení a ústí na žaludu (meatus) má tvar svislé štěrbiny, která formuje a usměrňuje proud moči.', '⚠️'),
('penis', '🧬 Lidská anatomie a biologie', '⚠️ Zajímavé anomálie a další specifika', 'Vzácnými vrozenými vývojovými vadami močové trubice jsou hypospadie (vyústění na spodní straně kmene) a epispadie (vyústění na horní straně penisu).', '⚠️'),
('penis', '📏 Velikost a statistiky', '📊 Skutečná čísla a průměry', 'Průměrná délka ztopořeného penisu podle rozsáhlých systematických studií (zahrnujících přes 15 000 mužů) je 13,12 cm a průměrný obvod činí 11,66 cm.', '📊'),
('penis', '📏 Velikost a statistiky', '📊 Skutečná čísla a průměry', 'V ochablém stavu měří průměrný penis 8,8 až 10 cm na délku a má obvod kolem 9,3 cm.', '📊'),
('penis', '📏 Velikost a statistiky', '📊 Skutečná čísla a průměry', 'Velikost penisu podléhá normálnímu (zvonovitému) statistickému rozložení – celých 68 % mužů spadá do standardního intervalu 11 až 15 centimetrů.', '📊'),
('penis', '📏 Velikost a statistiky', '📊 Skutečná čísla a průměry', 'Z evolučního hlediska má člověk (Homo sapiens) absolutně nejdelší a nejtlustší penis ze všech primátů v poměru k velikosti a váze těla.', '📊'),
('penis', '📏 Velikost a statistiky', '📊 Skutečná čísla a průměry', 'Většina celosvětových map velikostí je metodicky chybná, protože míchá přesná klinická měření s dotazníky (kde si muži běžně přidávají 1,5 až 2 cm). Při striktním měření zdravotníky se rozdíly mezi etniky zmenší na pouhý 1 až 2 centimetry.', '📊'),
('penis', '📏 Velikost a statistiky', '📊 Skutečná čísla a průměry', 'Správně se penis lékařsky měří tak, že se pravítko přitlačí z horní strany ke kořeni až na pánevní kost (čímž se stlačí podkožní tuk) a měří se přesně ke špičce žaludu.', '📊'),
('penis', '📏 Velikost a statistiky', '📊 Skutečná čísla a průměry', 'Při plné erekci se do penisu musí napumpovat 120 až 200 mililitrů krve (což zhruba odpovídá objemu menší sklenice na víno).', '📊'),
('penis', '📏 Velikost a statistiky', '📏 Extrémy a typy', 'Pouze 5 % dospělé mužské populace má v erekci penis delší než 16 cm a extrémní velikosti nad 20 cm se vyskytují u méně než 1 % mužů.', '📏'),
('penis', '📏 Velikost a statistiky', '📏 Extrémy a typy', 'Na opačném konci spektra platí, že asi 5 % mužů má v plné erekci penis kratší než 10 cm.', '📏'),
('penis', '📏 Velikost a statistiky', '📏 Extrémy a typy', 'Mikropenis je formální lékařská diagnóza pro orgán, který v dospělosti v erekci nedosahuje délky 7 cm (vyskytuje se u 0,6 % mužů, tedy zhruba u 1 z 200).', '📏'),
('penis', '📏 Velikost a statistiky', '📏 Extrémy a typy', 'Makropenis (velikost nad 18 cm) má statisticky asi 1 až 2 % mužské populace.', '📏'),
('penis', '📏 Velikost a statistiky', '📏 Extrémy a typy', 'Většina mužů patří do kategorie „growers“ (v klidu menší, při erekci se výrazně protáhnou – zvětšení o 85 % i více), zatímco menšina jsou „showers“ (v klidu vypadají velcí, ale při ztopoření povyrostou třeba jen o 30 %).', '📏'),
('penis', '📏 Velikost a statistiky', '📏 Extrémy a typy', 'Délka ochablého penisu nedokáže spolehlivě předpovědět délku v erekci. Naopak takzvaná „natažená délka“ ochablého penisu je v urologii velmi přesným odhadem.', '📏'),
('penis', '📏 Velikost a statistiky', '📏 Extrémy a typy', 'Největší komerčně vyráběné velikosti kondomů dokážou pojmout obvod penisu až 22 cm. Standardní kondomy bývají dlouhé 17–18 cm, což u mnoha průměrných mužů uměle posiluje pocit, že jsou malí, když kondom zcela nevyplní.', '📏'),
('penis', '📏 Velikost a statistiky', '🧠 Psychologie a ženské preference', 'Až 45 % mužů trpí nespokojeností ohledně velikosti svého genitálu. 80 % mužů totiž mylně věří, že celosvětový průměr je přes 15 cm.', '🧠'),
('penis', '📏 Velikost a statistiky', '🧠 Psychologie a ženské preference', 'Zkreslené vnímání normální velikosti je masivně ovlivněno pornografií, kam jsou statisticky vybíráni herci patřící do horních 1 až 5 % velikostní křivky.', '🧠'),
('penis', '📏 Velikost a statistiky', '🧠 Psychologie a ženské preference', 'Naopak zhruba 85 % žen uvádí, že jsou s velikostí partnerova penisu naprosto spokojeny, a pro dlouhodobý vztah preferují velikost jen mírně nad průměrem (kolem 15,2 cm na délku a 12,2 cm v obvodu).', '🧠'),
('penis', '📏 Velikost a statistiky', '🧠 Psychologie a ženské preference', 'Pro sexuální potěšení partnerky je často mnohem důležitější obvod (tloušťka) než samotná délka (heterosexuální ženy preferují obvod nad délkou v poměru 2:1).', '🧠'),
('penis', '📏 Velikost a statistiky', '🧠 Psychologie a ženské preference', 'Důvodem je anatomie – pouze první třetina pochvy (zhruba 5 až 7 cm) je hustě protkána nervovými zakončeními citlivými na dotek.', '🧠'),
('penis', '📏 Velikost a statistiky', '🧠 Psychologie a ženské preference', 'Extrémně velký penis představuje pro páry často reálný fyzický problém, protože narážení na děložní čípek bývá pro ženu velmi bolestivé.', '🧠'),
('penis', '📏 Velikost a statistiky', '🦄 Mýty a genetika', 'Neexistuje absolutně žádná vědecky prokázaná souvislost mezi velikostí bot (případně dlaní či nosu) a velikostí penisu.', '🦄'),
('penis', '📏 Velikost a statistiky', '🦄 Mýty a genetika', 'Vědci objevili, že existuje genetická souvislost mezi vývojem končetin a genitálií (sdílejí v embryu stejné Hox geny), z čehož historicky tento mýtus o velkých nohách vznikl.', '🦄'),
('penis', '📏 Velikost a statistiky', '🦄 Mýty a genetika', 'Tělesná výška muže vysvětluje pouze 5 až 10 % celkové variability délky penisu.', '🦄'),
('penis', '📏 Velikost a statistiky', '🦄 Mýty a genetika', 'Během těhotenství se budoucí velikost penisu zárodku určuje mezi 8. a 14. týdnem. Muži s velmi nízkou porodní hmotností mají v průměru o 0,5 cm kratší penis.', '🦄'),
('penis', '📏 Velikost a statistiky', '🦄 Mýty a genetika', 'Existuje slabá korelace s poměrem 2D:4D (délka ukazováčku ku prsteníčku) – nižší poměr značí vyšší prenatální expozici testosteronu a je mírně asociován s větším penisem.', '🦄'),
('penis', '📏 Velikost a statistiky', '🦄 Mýty a genetika', 'Jednovaječná dvojčata mají velmi podobnou délku penisu, ale nikoliv identickou (genetická dědičnost se pohybuje mezi 40 a 60 %).', '🦄'),
('penis', '📏 Velikost a statistiky', '📉 Co zmenšuje a zvětšuje velikost', 'Přibírání na váze penis fyzicky nezmenšuje, ale vrstva tuku na ohanbí ho opticky pohltí. Každých 15 kg nadváhy skryje zhruba 2 až 2,5 cm délky (a ztráta 10 kg je dokáže znovu odhalit). U obézních mužů (BMI > 30) je efektivní délka běžně o 2 cm kratší.', '📉'),
('penis', '📏 Velikost a statistiky', '📉 Co zmenšuje a zvětšuje velikost', 'V extrémním chladu („winter penis“) dochází k masivnímu stažení cév a ochablý penis se může zmenšit až o 50 % své délky a o 30 % svého objemu.', '📉'),
('penis', '📏 Velikost a statistiky', '📉 Co zmenšuje a zvětšuje velikost', 'Po 50. roce života se délka v erekci statisticky snižuje zhruba o 0,2 až 0,5 cm na dekádu v důsledku fibrotizace tkání a přirozené ztráty elasticity.', '📉'),
('penis', '📏 Velikost a statistiky', '📉 Co zmenšuje a zvětšuje velikost', 'Pravidelné kouření poškozuje cévy a může vést ke zmenšení ztopořeného penisu až o 1 cm. Zkrácení o 1 až 1,2 cm často nastává i po operaci prostaty nebo radioterapii pánve.', '📉'),
('penis', '📏 Velikost a statistiky', '📉 Co zmenšuje a zvětšuje velikost', 'Užívání anabolických steroidů penis nezmenšuje (zmenšují se varlata, protože tělo přestane tvořit vlastní testosteron).', '📉'),
('penis', '📏 Velikost a statistiky', '📉 Co zmenšuje a zvětšuje velikost', 'Užívání léků proti vypadávání vlasů (finasterid) může ve velmi vzácných případech způsobit trvalé zmenšení penisu (tzv. post-finasterid syndrom).', '📉'),
('penis', '📏 Velikost a statistiky', '📉 Co zmenšuje a zvětšuje velikost', 'Neexistuje žádná magická pilulka ani krém pro zvětšení penisu. Jde o čistý marketingový podvod.', '📉'),
('penis', '📏 Velikost a statistiky', '📉 Co zmenšuje a zvětšuje velikost', 'Zvětšení obvodu injekcemi vlastního tuku nebo kyseliny hyaluronové má velmi nejisté výsledky (tuk se vstřebává nerovnoměrně a tvoří hrudky).', '📉'),
('penis', '📏 Velikost a statistiky', '📉 Co zmenšuje a zvětšuje velikost', 'Chirurgické prodloužení (přeříznutí závěsného vazu) sice přidá 1 až 2 cm v ochablém stavu, ale při erekci penis ztratí stabilitu a směřuje dolů. Až 50 % mužů je po plastice penisu s výsledkem nespokojeno.', '📉'),
('penis', '📏 Velikost a statistiky', '📉 Co zmenšuje a zvětšuje velikost', 'Pravidelné používání trakčních zařízení (která penis fyzicky natahují) může klinicky přidat 1 až 2 centimetry na délce, ale vyžaduje to nošení přístroje několik hodin denně po dobu mnoha měsíců.', '📉'),
('penis', '📏 Velikost a statistiky', '🏆 Kuriózní rekordy', 'Neoficiální rekordman v délce lidského penisu, Američan Jonah Falcon, tvrdí, že jeho penis měří v klidu 24 cm a při erekci 34 cm. (Guinnessův rekord uvádí i Roberta Esmieho s 34,3 cm, ale bez standardizovaného měření).', '🏆'),
('penis', '📏 Velikost a statistiky', '🏆 Kuriózní rekordy', 'Mexičan Roberto Esquivel Cabrera se proslavil penisem dlouhým údajně 48 centimetrů. Lékaři však na rentgenu zjistili, že samotný penis měří jen asi 16 cm a zbytek tvoří pouze abnormálně vytahaná předkožka a zanícená tkáň.', '🏆'),
('penis', '🐋 Extrémy zvířecí říše.', '🐋 Giganti a velcí savci', 'Plejtvák obrovský má absolutně největší penis na světě. V erekci může dosahovat délky 2,5 až 3 metry, má průměr přes 30 centimetrů a váží přes 400 kilogramů.', '🐋'),
('penis', '🐋 Extrémy zvířecí říše.', '🐋 Giganti a velcí savci', 'Slon africký má nesmírně mohutný a svalnatý penis dlouhý asi 1,5 metru (vážící 20–30 kg). Je natolik pohyblivý (prehensilní), že ho slon může používat v podstatě jako pátou končetinu a odhánět jím mouchy z břicha.', '🐋'),
('penis', '🐋 Extrémy zvířecí říše.', '🐋 Giganti a velcí savci', 'Nosorožec má penis dlouhý až 80 centimetrů, který v klidu směřuje dozadu a na konci má dva výrazné postranní laloky. Aby se mohl spářit, musí ho během ztopoření svalově ohnout do velkého oblouku pod své břicho dopředu.', '🐋'),
('penis', '🐋 Extrémy zvířecí říše.', '🐋 Giganti a velcí savci', 'Hroch má genitálie uspořádané rovněž tak, že penis směřuje dozadu. Při močení tak proud směřuje na jeho neustále kmitající ocas, kterým rozprašuje moč a trus na všechny strany, aby si značkoval teritorium. Při páření se samec logicky staví k samici zády.', '🐋'),
('penis', '🐋 Extrémy zvířecí říše.', '🐋 Giganti a velcí savci', 'Velbloud má penis dlouhý asi 60 centimetrů, který se při erekci vyklání z předkožky směrem dozadu.', '🐋'),
('penis', '🐋 Extrémy zvířecí říše.', '🐋 Giganti a velcí savci', 'Tapír se pyšní obrovským uchopovacím penisem, který může u dospělého samce sahat až na zem. Slouží k usnadnění páření v hluboké vodě nebo bahně, kde se zvířata nemohou normálně pohybovat.', '🐋'),
('penis', '🐋 Extrémy zvířecí říše.', '🐋 Giganti a velcí savci', 'Delfíni mají svalnatý, vysoce pohyblivý penis, který dokážou používat nejen k rozmnožování, ale i jako hmatový orgán k prozkoumávání objektů, k hravému tahání jiných delfínů za ploutve nebo k masturbaci.', '🐋'),
('penis', '🐋 Extrémy zvířecí říše.', '🐋 Giganti a velcí savci', 'Kůň má ztopořený penis dlouhý 40–50 centimetrů s výrazným žaludem ve tvaru hřibu. Při vzrušení a nasávání feromonů samice provádí takzvané flehmování (vyhrne horní pysk).', '🐋'),
('penis', '🐋 Extrémy zvířecí říše.', '🐋 Giganti a velcí savci', 'Mláďata žiraf se musí naučit manévr, kdy samec pošťouchne samici hlavou do slabin, aby ji donutil vymočit se. Moč pak ochutná na jazyku, a pokud zjistí říji, dochází k extrémně rychlé kopulaci trvající sotva pár sekund.', '🐋'),
('penis', '🐋 Extrémy zvířecí říše.', '🦴 Kosti v penisu, trny a háčky', 'Většina primátů (mimo člověka a gorily), šelmy a mnozí další savci mají v penisu kost zvanou bakulum, která usnadňuje ztopoření bez nutnosti plného cévního napětí.', '🦴'),
('penis', '🐋 Extrémy zvířecí říše.', '🦴 Kosti v penisu, trny a háčky', 'Mroži vlastní absolutně největší penisovou kost ze všech savců. Měří zhruba 60 centimetrů a je tak masivní, že z ní domorodé kmeny na severu vyráběly kyje zvané oosik.', '🦴'),
('penis', '🐋 Extrémy zvířecí říše.', '🦴 Kosti v penisu, trny a háčky', 'Medvědi mají bakulum dlouhé až 20 centimetrů, které jim slouží jako pevná opora při erekci.', '🦴'),
('penis', '🐋 Extrémy zvířecí říše.', '🦴 Kosti v penisu, trny a háčky', 'Mýval severní má penisovou kost na konci specificky zahnutou do tvaru háčku. V americkém folklóru se tyto kosti často vyvařovaly a nosily jako amulety pro štěstí.', '🦴'),
('penis', '🐋 Extrémy zvířecí říše.', '🦴 Kosti v penisu, trny a háčky', 'Kočkovité šelmy (včetně kocoura domácího a lvů) mají na penisu keratinové háčky či ostny. Ty při vytahování z pochvy drásají stěny vagíny, což samici sice způsobuje bolest (proto kočky křičí), ale spouští to nezbytnou ovulaci.', '🦴'),
('penis', '🐋 Extrémy zvířecí říše.', '🦴 Kosti v penisu, trny a háčky', 'Prasata mají penis stočený do tvaru spirály (vývrtky). Samci prasat divokých dokážou ejakulovat nepřetržitě i déle než pět minut v dávkách a vyprodukují při tom neuvěřitelný půl litr semene.', '🦴'),
('penis', '🐋 Extrémy zvířecí říše.', '🦴 Kosti v penisu, trny a háčky', 'Psi a další psovité šelmy mají na kořeni penisu zduřeninu zvanou bulbus glandis. Ta se během páření uvnitř feny extrémně zvětší, čímž dojde ke „svázání“ páru, které může trvat až 30 minut.', '🦴'),
('penis', '🐋 Extrémy zvířecí říše.', '🦴 Kosti v penisu, trny a háčky', 'Alpaky a lamy mají u kořene penisu pevnou chrupavčitou strukturu. Ta při páření mechanicky stimuluje děložní čípek, protože ovulace u nich neprobíhá cyklicky, ale je vyvolána až hrubým fyzickým aktem kopulace.', '🦴'),
('penis', '🐋 Extrémy zvířecí říše.', '🦘 Bizarní anatomie vačnatců a primátů', 'Klokani (a vakovlci) mají anatomii genitálií uspořádanou opačně – jejich šourek se nachází před penisem, nikoliv za ním. Penis mají na konci rozštěpený na dvě špičky (bifidní), což přesně odpovídá anatomii samic, které mají hned tři vagíny.', '🦘'),
('penis', '🐋 Extrémy zvířecí říše.', '🦘 Bizarní anatomie vačnatců a primátů', 'Ptakořitní savci, jako je ježura australská a ptakopysk, se mohou pochlubit rovnou čtyřhlavým penisem. Při páření se ztopoří vždy jen dvě hlavy na jedné straně, zatímco druhé dvě odpočívají. Při dalším páření se strany vystřídají.', '🦘'),
('penis', '🐋 Extrémy zvířecí říše.', '🦘 Bizarní anatomie vačnatců a primátů', 'Drobní australští vačnatci rodu Antechinus se v období páření oddávají sexuálním maratonům (až 14 hodin v kuse), což je vyčerpá natolik, že jim z kolapsu imunitního systému selžou orgány a všichni samci hromadně uhynou.', '🦘'),
('penis', '🐋 Extrémy zvířecí říše.', '🦘 Bizarní anatomie vačnatců a primátů', 'Šimpanzi mají penis, který v erekci měří v průměru pouhých 8 centimetrů, zato mají obrovská varlata kvůli extrémní spermiové konkurenci (samice se páří s mnoha samci).', '🦘'),
('penis', '🐋 Extrémy zvířecí říše.', '🦘 Bizarní anatomie vačnatců a primátů', 'Nejméně obdařeným velkým lidoopem je obří stříbrohřbetá gorila. Její penis měří v erekci pouhé 3–4 centimetry. Nevyžadoval totiž evoluční tlak, protože dominantní samec má svůj harém jistý a nemusí soutěžit s jinými.', '🦘'),
('penis', '🐋 Extrémy zvířecí říše.', '🦘 Bizarní anatomie vačnatců a primátů', 'Samice hyeny skvrnité mají hypertrofovaný klitoris, který vypadá, visí a funguje úplně stejně jako penis samce. Samice přes tento pseudo-penis močí, páří se a dokonce přes něj i rodí mláďata.', '🦘'),
('penis', '🐋 Extrémy zvířecí říše.', '🦘 Bizarní anatomie vačnatců a primátů', 'Surikaty mají hierarchickou výbavu: alfa samec má prokazatelně větší penis než jeho podřízení, což přímo souvisí s jeho dominancí.', '🦘'),
('penis', '🐋 Extrémy zvířecí říše.', '🦘 Bizarní anatomie vačnatců a primátů', 'Netopýři mají během letu často samovolnou erekci. Některé druhy (např. netopýr večerní) mají penis natolik široký, že se fyzicky vůbec nevejde do pochvy samice, takže funguje jen jako „kontaktní orgán“, kterým přitiskne semeno zvenčí k vulvě.', '🦘'),
('penis', '🐋 Extrémy zvířecí říše.', '🦅 Ptáci, plazi a jejich zbraně', 'Až 97 % všech druhů ptáků (například slepice, holubi, dravci jako orli nebo čápi) nemá vůbec žádný vnější penis a rozmnožují se pouze „kloakálním polibkem“, kdy k sobě na zlomek sekundy přitisknou vylučovací otvory.', '🦅'),
('penis', '🐋 Extrémy zvířecí říše.', '🦅 Ptáci, plazi a jejich zbraně', 'Výjimkou mezi ptáky jsou běžci (např. pštros, jehož penis je při ztopoření 20 cm dlouhý, růžový a špičatý) a vrubozobí (kachny a husy).', '🦅'),
('penis', '🐋 Extrémy zvířecí říše.', '🦅 Ptáci, plazi a jejich zbraně', 'Kačeři mají spirálovitý penis ve tvaru vývrtky (u kachny argentinské měří až 42 cm, tedy více než tělo zvířete). Dokáže explozivně erektovat za méně než půl sekundy. Samice si proto vyvinuly vagínu se slepými chodbičkami a opačným závitem, aby se chránily před znásilněním.', '🦅'),
('penis', '🐋 Extrémy zvířecí říše.', '🦅 Ptáci, plazi a jejich zbraně', 'Hadi a ještěrky (včetně varana komodského) nemají jeden penis, ale tzv. hemipenisy – párový orgán uložený v kapsách u kořene ocasu. Při páření vyklopí jen ten na straně samice. Bývají zdobené háčky k ukotvení a mají rýhu (sulcus spermaticus), kterou proudí sperma.', '🦅'),
('penis', '🐋 Extrémy zvířecí říše.', '🦅 Ptáci, plazi a jejich zbraně', 'Krokodýli mají penis, který je trvale tvrdý díky kolagenové struktuře (neplní se krví) a je neustále schovaný uvnitř kloaky. Při páření ho ven doslova vymrští svalový mechanismus.', '🦅'),
('penis', '🐋 Extrémy zvířecí říše.', '🦅 Ptáci, plazi a jejich zbraně', 'Většina suchozemských želv má nepárový, hrozivě vypadající, masitý penis uložený v kloace. Při ztopoření se z ní vyvalí ven, přičemž často připomíná obrovskou fialovou květinu.', '🦅'),
('penis', '🐋 Extrémy zvířecí říše.', '🦅 Ptáci, plazi a jejich zbraně', 'Dinosauři (např. Ankylosaurus) měli podle vědců genitálie pravděpodobně schované v kloace podobně jako dnešní krokodýli, měkké tkáně se ale ve fosiliích nedochovaly.', '🦅'),
('penis', '🐋 Extrémy zvířecí říše.', '🐙 Podvodní svět a šampioni v poměru k tělu', 'V poměru k velikosti těla je absolutním rekordmanem vilejš stvolnatý (svijonožec přisedlý na skalách). Jeho penis je až osmkrát delší než jeho tělo, aby vůbec dosáhl na sousedy v kolonii.', '🐙'),
('penis', '🐋 Extrémy zvířecí říše.', '🐙 Podvodní svět a šampioni v poměru k tělu', 'Chobotnice a krakatice tvoří spermatofory (ostré kapsle se spermatem). Argonaut pelagický má modifikované chapadlo (hektokotylus), které se od něj odtrhne a samo doplave do samice. Samec kalmara obrovského má metrový penis, kterým jako vysokotlakou hadicí nastřeluje kapsle pod kůži samic.', '🐙'),
('penis', '🐋 Extrémy zvířecí říše.', '🐙 Podvodní svět a šampioni v poměru k tělu', 'Žraloci a rejnoci nemají skutečný penis. Místo něj používají takzvané pterygopody (claspers), což jsou dvě srolované a ztvrdlé břišní ploutve.', '🐙'),
('penis', '🐋 Extrémy zvířecí říše.', '🐙 Podvodní svět a šampioni v poměru k tělu', 'U mořských koníků panuje dokonalá výměna rolí: samec žádný penis nemá, naopak samice má trubičkovité kladélko, kterým vpraví svá vajíčka do břišního vaku samce, a ten je odnosí a porodí.', '🐙'),
('penis', '🐋 Extrémy zvířecí říše.', '🐙 Podvodní svět a šampioni v poměru k tělu', 'Hlubokomořští ďasové mají extrémní přístup: zakrnělý samec bez genitálií se zakousne do obří samice, postupně s ní sroste, ztratí mozek i oči a zbyde z něj jen trvalý přívěsek produkující spermie.', '🐙'),
('penis', '🐋 Extrémy zvířecí říše.', '🐙 Podvodní svět a šampioni v poměru k tělu', 'Akvarijní rybky (paví očka neboli živorodky) a pyskouni mají místo penisu takzvané gonopodium – do trubičky upravenou řitní ploutev. U některých pyskounů samec dokonce mění pohlaví na samici a penis se mu změní v kladélko.', '🐙'),
('penis', '🐋 Extrémy zvířecí říše.', '🐙 Podvodní svět a šampioni v poměru k tělu', 'Mořští plochštěnci jsou hermafroditi. Při setkání spolu „šermují penisy“ a ten, komu se podaří jako prvnímu bodnout partnera a vpravit do něj spermie, se stává otcem. Poražený musí přijmout roli matky.', '🐙'),
('penis', '🐋 Extrémy zvířecí říše.', '🐙 Podvodní svět a šampioni v poměru k tělu', 'Nahožábří plži rodu Chromodoris dokážou po páření svůj penis amputovat a během následujících 24 hodin jim v těle doroste zcela nový.', '🐙'),
('penis', '🐋 Extrémy zvířecí říše.', '🪲 Hmyz, červi a mikrosvět', 'Banánový slimák a hlemýžď zahradní jsou hermafroditi s penisem často delším, než je jejich tělo. Někdy se při páření natolik zaseknou, že je nutné penis odkusnout (tzv. apofalace), aby se vůbec rozdělili.', '🪲'),
('penis', '🐋 Extrémy zvířecí říše.', '🪲 Hmyz, červi a mikrosvět', 'Trubci (samci včely medonosné) při svatebním letu doslova explodují. Jejich genitálie se pod obrovským tlakem vyklopí ven, vtlačí do královny s hlasitým lupnutím a odtrhnou se, což způsobí smrt trubce.', '🪲'),
('penis', '🐋 Extrémy zvířecí říše.', '🪲 Hmyz, červi a mikrosvět', 'Pavouci fyziologicky žádný penis nemají. K přenosu spermií používají speciálně upravená makadla (pedipalpy) u tlamy, která fungují jako pipety a po kopulaci se často ulomí.', '🪲'),
('penis', '🐋 Extrémy zvířecí říše.', '🪲 Hmyz, červi a mikrosvět', 'Blechy mají absolutně nejsložitější uspořádání genitálií. Jejich penis funguje jako mikroskopický švýcarský nůž plný pružin, destiček a kartáčků.', '🪲'),
('penis', '🐋 Extrémy zvířecí říše.', '🪲 Hmyz, červi a mikrosvět', 'Škvoři mají dva plně funkční penisy uložené vedle sebe (pravý a levý). Téměř vždy používají pravý, levý slouží jen jako náhrada, kdyby se pravý ulomil.', '🪲'),
('penis', '🐋 Extrémy zvířecí říše.', '🪲 Hmyz, červi a mikrosvět', 'Samci štěnice domácí nepoužívají přirozený pohlavní otvor samice. Mají penis ostrý jako jehla, kterým samici jednoduše probodnou břicho a vstříknou spermie přímo do těla (traumatická inseminace).', '🪲'),
('penis', '🐋 Extrémy zvířecí říše.', '🪲 Hmyz, červi a mikrosvět', 'Vodoměrky používají svůj penis k vydírání. Samec na samici naskočí, a pokud ho odmítne, začne genitáliemi bubnovat do vodní hladiny, čímž úmyslně láká dravé ryby, dokud samice nepovolí.', '🪲'),
('penis', '🐋 Extrémy zvířecí říše.', '🪲 Hmyz, červi a mikrosvět', 'Samci křečků mají enormně velká varlata, která mohou tvořit až čtvrtinu jejich hmotnosti, a jejich malý penis obsahuje drobnou kůstku.', '🪲'),
('penis', '🐋 Extrémy zvířecí říše.', '🪲 Hmyz, červi a mikrosvět', 'Samec tasemnice má rovnou dva penisy. Vzhledem ke svému parazitickému způsobu života je často používá k inseminaci vlastního těla (samooplození).', '🪲'),
('penis', '🐋 Extrémy zvířecí říše.', '🪲 Hmyz, červi a mikrosvět', 'Krabi mají penis velmi netradičně umístěný na posledním páru nohou.', '🪲'),
('penis', '🐋 Extrémy zvířecí říše.', '🪲 Hmyz, červi a mikrosvět', 'U myší se spermie dokážou spojovat jako vagony vlaku. Mají na hlavičkách drobné háčky, díky kterým se shluknou a plavou k vajíčku mnohem rychleji než osamocená spermie konkurenta.', '🪲'),
('penis', '🏛️ Historie a kultura', '🏺 Prehistorie a antický svět (Řecko, Řím, Egypt)', 'Nejstarší známý umělecký předmět zobrazující falus je hladký kámen (vyřezaný z prachovce/břidlice) nalezený v jeskyni Hohle Fels v Německu. Je starý neuvěřitelných 28 000 let a pravděpodobně sloužil jako primitivní dildo.', '🏺'),
('penis', '🏛️ Historie a kultura', '🏺 Prehistorie a antický svět (Řecko, Řím, Egypt)', 'V antických Pompejích byly do kamenné dlažby vytesány symboly penisů, které prokazatelně fungovaly jako směrovky ukazující cestu cizincům a námořníkům k nejbližšímu nevěstinci (lupanáriu).', '🏺'),
